content.text:
Vektor yaratmaq üçün `<vector>` başlıq faylı daxil edilir və aşağıdakı sintaksisdən istifadə olunur:
#include <vector>
std::vector<data_type> vector_name;
Məsələn, `std::vector<int> numbers;` tam ədədləri saxlayan bir vektor yaradır.

content.code:
#include <iostream>
#include <vector>
#include <string>

int main() {
  std::vector<int> numbers;
  numbers.push_back(10);
  numbers.push_back(20);
  numbers.push_back(30);
  for(int i = 0; i < numbers.size(); i++) {
    std::cout << numbers[i] << " ";
  }
  std::cout << std::endl;
  return 0;
}
// Output:
// 10 20 30

#include <iostream>
#include <vector>
#include <string>

int main() {
  std::vector<std::string> names;
  names.push_back("Ali");
  names.push_back("Veli");
  std::cout << "Size: " << names.size() << std::endl;
  std::cout << "First name: " << names.at(0) << std::endl;
  names.pop_back();
  std::cout << "Size after pop: " << names.size() << std::endl;
  return 0;
}
// Output:
// Size: 2
// First name: Ali
// Size after pop: 1

#include <iostream>
#include <vector>

int main() {
  std::vector<int> numbers;
  for(int i = 1; i <= 5; i++) {
    numbers.push_back(i * 10);
  }
  for(int num : numbers) {
    std::cout << num << " ";
  }
  std::cout << std::endl;
  return 0;
}
// Output:
// 10 20 30 40 50

#include <iostream>
#include <vector>

int main() {
  std::vector<int> numbers = {1, 2, 3, 4, 5};
  for(auto it = numbers.begin(); it != numbers.end(); ++it) {
    std::cout << *it << " ";
  }
  std::cout << std::endl;
  return 0;
}
// Output:
// 1 2 3 4 5

